# auth.py - User Authentication Module
# WARNING: This file is too large. Consider refactoring.

import hashlib
import secrets
import jwt
from datetime import datetime, timedelta
from flask import request, jsonify, session
from database import db
from models import User, Session, APIKey, OAuthToken
from email_service import send_email
from rate_limiter import rate_limit

# ===== LOGIN SECTION =====

def login(email: str, password: str) -> dict:
    """Authenticate user with email and password."""
    user = User.query.filter_by(email=email).first()
    if not user:
        return {'error': 'Invalid credentials', 'status': 401}
    if not verify_password(password, user.password_hash):
        record_failed_attempt(user)
        return {'error': 'Invalid credentials', 'status': 401}
    if user.is_locked:
        return {'error': 'Account locked. Contact support.', 'status': 403}
    if user.requires_mfa:
        return {'mfa_required': True, 'mfa_token': generate_mfa_token(user)}
    session_token = create_session(user)
    return {'token': session_token, 'user': user.to_dict()}

def verify_password(password: str, hash: str) -> bool:
    return hashlib.pbkdf2_hmac('sha256', password.encode(), b'salt', 100000).hex() == hash

def record_failed_attempt(user: User):
    user.failed_attempts += 1
    if user.failed_attempts >= 5:
        user.is_locked = True
        user.locked_at = datetime.utcnow()
    db.session.commit()

def create_session(user: User) -> str:
    token = secrets.token_urlsafe(32)
    session = Session(user_id=user.id, token=token, expires_at=datetime.utcnow() + timedelta(hours=24))
    db.session.add(session)
    db.session.commit()
    return token

def logout(token: str):
    session = Session.query.filter_by(token=token).first()
    if session:
        db.session.delete(session)
        db.session.commit()

# ===== REGISTRATION SECTION =====

def register(email: str, password: str, name: str) -> dict:
    if User.query.filter_by(email=email).first():
        return {'error': 'Email already registered', 'status': 409}
    if not validate_password_strength(password):
        return {'error': 'Password does not meet requirements', 'status': 400}
    password_hash = hash_password(password)
    user = User(email=email, password_hash=password_hash, name=name)
    verification_token = secrets.token_urlsafe(32)
    user.verification_token = verification_token
    db.session.add(user)
    db.session.commit()
    send_email(email, 'Verify your account', f'Click here to verify: /verify?token={verification_token}')
    return {'message': 'Registration successful. Check your email.', 'status': 201}

def verify_email(token: str) -> dict:
    user = User.query.filter_by(verification_token=token).first()
    if not user:
        return {'error': 'Invalid verification token', 'status': 400}
    user.is_verified = True
    user.verification_token = None
    db.session.commit()
    return {'message': 'Email verified successfully'}

def validate_password_strength(password: str) -> bool:
    if len(password) < 8:
        return False
    has_upper = any(c.isupper() for c in password)
    has_lower = any(c.islower() for c in password)
    has_digit = any(c.isdigit() for c in password)
    has_special = any(c in '!@#$%^&*()_+-=' for c in password)
    return all([has_upper, has_lower, has_digit, has_special])

# ===== PASSWORD RESET SECTION =====

def request_password_reset(email: str) -> dict:
    user = User.query.filter_by(email=email).first()
    if not user:
        return {'message': 'If account exists, reset email sent.'}
    reset_token = secrets.token_urlsafe(32)
    user.reset_token = reset_token
    user.reset_token_expires = datetime.utcnow() + timedelta(hours=1)
    db.session.commit()
    send_email(email, 'Password Reset', f'Reset link: /reset?token={reset_token}')
    return {'message': 'If account exists, reset email sent.'}

def reset_password(token: str, new_password: str) -> dict:
    user = User.query.filter_by(reset_token=token).first()
    if not user or user.reset_token_expires < datetime.utcnow():
        return {'error': 'Invalid or expired reset token', 'status': 400}
    if not validate_password_strength(new_password):
        return {'error': 'Password does not meet requirements', 'status': 400}
    user.password_hash = hash_password(new_password)
    user.reset_token = None
    user.reset_token_expires = None
    user.failed_attempts = 0
    user.is_locked = False
    db.session.commit()
    return {'message': 'Password reset successful'}

# ===== OAUTH SECTION =====

def oauth_callback(provider: str, code: str) -> dict:
    if provider == 'google':
        token_data = exchange_google_code(code)
    elif provider == 'github':
        token_data = exchange_github_code(code)
    else:
        return {'error': f'Unsupported provider: {provider}', 'status': 400}
    user_info = get_oauth_user_info(provider, token_data['access_token'])
    user = User.query.filter_by(oauth_provider=provider, oauth_id=user_info['id']).first()
    if not user:
        user = User(email=user_info['email'], name=user_info['name'], oauth_provider=provider, oauth_id=user_info['id'], is_verified=True)
        db.session.add(user)
    oauth_token = OAuthToken(user_id=user.id, provider=provider, access_token=token_data['access_token'], refresh_token=token_data.get('refresh_token'), expires_at=datetime.utcnow() + timedelta(seconds=token_data['expires_in']))
    db.session.add(oauth_token)
    db.session.commit()
    session_token = create_session(user)
    return {'token': session_token, 'user': user.to_dict()}

# ===== API KEY SECTION =====

def create_api_key(user_id: int, name: str, scopes: list) -> dict:
    key = f'ak_{secrets.token_urlsafe(32)}'
    key_hash = hashlib.sha256(key.encode()).hexdigest()
    api_key = APIKey(user_id=user_id, name=name, key_hash=key_hash, scopes=scopes, created_at=datetime.utcnow())
    db.session.add(api_key)
    db.session.commit()
    return {'key': key, 'name': name, 'scopes': scopes, 'message': 'Save this key - it will not be shown again'}

def validate_api_key(key: str) -> dict:
    key_hash = hashlib.sha256(key.encode()).hexdigest()
    api_key = APIKey.query.filter_by(key_hash=key_hash).first()
    if not api_key or api_key.is_revoked:
        return {'error': 'Invalid API key', 'status': 401}
    api_key.last_used = datetime.utcnow()
    api_key.use_count += 1
    db.session.commit()
    return {'user_id': api_key.user_id, 'scopes': api_key.scopes}

# ===== MIDDLEWARE SECTION =====

def auth_required(f):
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization', '').replace('Bearer ', '')
        if not token:
            return jsonify({'error': 'Authentication required'}), 401
        session = Session.query.filter_by(token=token).first()
        if not session or session.expires_at < datetime.utcnow():
            return jsonify({'error': 'Invalid or expired session'}), 401
        request.current_user = session.user
        return f(*args, **kwargs)
    return decorated
